                ['type' => 'h2', 'text' => '11. Changes'],
                ['type' => 'p',  'text' => 'We reserve the right to update this Privacy Policy. In case of material changes, we will notify you through the Service. Continued use of the Service after the changes are published constitutes acceptance of them.'],
